"use client";

import { useEffect, useMemo, useState } from "react";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Filter, List, Search } from "lucide-react";
import { bookingsMock, statusCopy, type Booking, type BookingStatus } from "../data";
import { Calendar, MapPin } from "lucide-react";

const variantConfig = {
  upcoming: {
    title: "Upcoming Appointments",
    description: "Keep track of your pending and confirmed visits.",
    emptyMessage: "You don't have any upcoming appointments right now.",
  },
  previous: {
    title: "Previous Appointments",
    description: "Review the services you've already completed.",
    emptyMessage: "No completed appointments found.",
  },
  cancelled: {
    title: "Cancelled Appointments",
    description: "See the bookings you've decided to call off.",
    emptyMessage: "No cancelled appointments on record.",
  },
} as const;

export type AppointmentsVariant = keyof typeof variantConfig;

function filterBookings(bookings: Booking[], variant: AppointmentsVariant) {
  if (variant === "upcoming") {
    const startOfToday = new Date(new Date().toDateString());
    return bookings.filter((booking) => {
      const bookingDate = new Date(booking.date);
      return booking.status === "confirmed" && bookingDate >= startOfToday;
    });
  }

  if (variant === "previous") {
    return bookings.filter((booking) => booking.status === "completed");
  }

  if (variant === "cancelled") {
    return bookings.filter((booking) => booking.status === "cancelled");
  }

  return bookings;
}

const StatusBadge = ({ status }: { status: BookingStatus }) => (
  <Badge className={`inline-flex items-center gap-1 px-2.5 py-1 ${statusCopy[status].tone}`}>
    {statusCopy[status].label}
  </Badge>
);

export function AppointmentsView({ variant }: { variant: AppointmentsVariant }) {
  const [customerEmail, setCustomerEmail] = useState<string | null>(null);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const storedEmail = localStorage.getItem("customerEmail");
    setCustomerEmail(storedEmail);
  }, []);

  const bookings = useMemo(() => {
    if (!customerEmail) return [];
    const customerBookings = bookingsMock.filter((booking) => booking.email === customerEmail);
    return filterBookings(customerBookings, variant);
  }, [customerEmail, variant]);

  const config = variantConfig[variant];

  return (
    <div className="space-y-6">
      <Card className="border border-border/70 shadow-sm">
        <CardHeader className="border-b border-border/70 pb-4 space-y-4">
          <div className="flex flex-col gap-2 lg:flex-row lg:items-center lg:justify-between">
            <div>
              <h2 className="text-2xl font-semibold tracking-tight text-foreground">{config.title}</h2>
              <p className="text-sm text-muted-foreground">{config.description}</p>
            </div>
            <Badge variant="outline" className="rounded-full px-3 py-1 text-xs font-medium w-fit">
              {bookings.length} record{bookings.length === 1 ? "" : "s"}
            </Badge>
          </div>

          <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
            <div className="flex flex-1 items-center gap-3">
              <div className="relative flex-1">
                <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                <Input placeholder="Search bookings..." className="pl-10" />
              </div>
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="outline" className="gap-2">
                    <Filter className="h-4 w-4" /> All Status
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="start" className="w-40">
                  <DropdownMenuItem>All</DropdownMenuItem>
                  <DropdownMenuItem>Pending</DropdownMenuItem>
                  <DropdownMenuItem>Confirmed</DropdownMenuItem>
                  <DropdownMenuItem>Completed</DropdownMenuItem>
                  <DropdownMenuItem>Cancelled</DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
            <Button className="bg-primary text-primary-foreground hover:bg-primary/90">Add Booking</Button>
          </div>
        </CardHeader>
        <CardContent className="p-0">
          {bookings.length === 0 ? (
            <div className="flex flex-col items-center justify-center gap-3 px-6 py-12 text-center">
              <div className="rounded-full bg-muted p-3">
                <Calendar className="h-5 w-5 text-muted-foreground" />
              </div>
              <div>
                <p className="text-sm text-muted-foreground">{config.emptyMessage}</p>
                <p className="text-xs text-muted-foreground">Check back soon or schedule a new service.</p>
              </div>
            </div>
          ) : (
            <ul className="divide-y divide-border/70">
              {bookings.map((booking) => (
                <li key={booking.id} className="p-5">
                  <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
                    <div className="space-y-1">
                      <p className="text-sm font-semibold text-foreground">{booking.service}</p>
                      <p className="text-sm text-muted-foreground">
                        {booking.date} • {booking.time}
                      </p>
                    </div>
                    <StatusBadge status={booking.status} />
                  </div>

                  <div className="mt-4 grid gap-4 md:grid-cols-3">
                    <div>
                      <p className="text-xs uppercase tracking-wide text-muted-foreground">Location</p>
                      <p className="mt-1 text-sm text-foreground">
                        <MapPin className="mr-1 inline h-3.5 w-3.5 text-muted-foreground" />
                        {booking.address}
                      </p>
                    </div>
                    <div>
                      <p className="text-xs uppercase tracking-wide text-muted-foreground">Notes</p>
                      <p className="mt-1 text-sm text-foreground">{booking.instructions || "—"}</p>
                    </div>
                    <div className="flex flex-wrap gap-4 md:justify-end">
                      <div>
                        <p className="text-xs uppercase tracking-wide text-muted-foreground">Booking ID</p>
                        <p className="mt-1 text-sm font-medium text-foreground">{booking.id}</p>
                      </div>
                      <div>
                        <p className="text-xs uppercase tracking-wide text-muted-foreground">Amount</p>
                        <p className="mt-1 text-lg font-semibold text-foreground">${booking.amount.toFixed(2)}</p>
                      </div>
                    </div>
                  </div>
                </li>
              ))}
            </ul>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
